const fetchBootstrapData = (contextid, cmid) => {
    debugLog(null, 'Bootstrap AJAX request queued', {
        contextid,
        cmid,
    });
    return fetchMany([{
        methodname: 'local_processfeedback_get_bootstrap_data',
        args: {
            contextid,
            cmid,
        },
    }])[0];
};
return { fetchBootstrapData };
